import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"TheSequence — 2026-04-05","description":"","frontmatter":{"title":"TheSequence — 2026-04-05","date":"2026-04-05T00:00:00.000Z","source":"TheSequence","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-05-thesequence.md","filePath":"research/ai-news/2026-04/2026-04-05-thesequence.md","lastUpdated":1779894392000}'),i={name:"research/ai-news/2026-04/2026-04-05-thesequence.md"};function o(s,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔢-thesequence-—-2026-04-05" tabindex="-1">🔢 TheSequence — 2026-04-05 <a class="header-anchor" href="#🔢-thesequence-—-2026-04-05" aria-label="Permalink to &quot;🔢 TheSequence — 2026-04-05&quot;">​</a></h1><blockquote><p>165k+ 訂閱；ML / 企業 AI 應用週報，Jesus Rodriguez 主筆 來源：<a href="https://thesequence.substack.com/feed" target="_blank" rel="noreferrer">TheSequence</a></p></blockquote><hr><h2 id="the-sequence-radar-837-last-week-in-ai-from-model-releases-to-market-structure" tabindex="-1"><a href="https://thesequence.substack.com/p/the-sequence-radar-837-last-week" target="_blank" rel="noreferrer">The Sequence Radar #837: Last Week in AI: From Model Releases to Market Structure</a> <a class="header-anchor" href="#the-sequence-radar-837-last-week-in-ai-from-model-releases-to-market-structure" aria-label="Permalink to &quot;[The Sequence Radar #837: Last Week in AI: From Model Releases to Market Structure](https://thesequence.substack.com/p/the-sequence-radar-837-last-week)&quot;">​</a></h2><p><em>🔢 TheSequence | 2026-04-05</em></p><p>Next Week in The Sequence:</p><p>We continue our series about world models</p><p>The AI of the week section will dive into the amazing Gemma4.</p><p>The opinion section will discuss why every piece of software infrastructure needs to be rewritten for AI agents.</p><p>Subscribe and don’t miss out:</p><p>📝 Editorial: Last Week in AI: From Model Releases to Market Structure</p><p>This week in AI was not really a product week. It was a market-structure week. OpenAI’s massive new funding round, Microsoft’s release of new models, Google’s expansion of Gemma 4, and the arrival of GLM-5V Turbo all pointed to the same conclusion: the center of gravity in AI is shifting. The industry is no longer organized around who has the most impressive demo. It is being reorganized around who can finance, deploy, compress, distribute, and operationalize intelligence at scale. AI is starting to look less like software and more like infrastructure.</p><p>OpenAI’s round was the loudest signal. At some level, every frontier AI company is now running two races at once: a research race and a capital race. The models matter, of course, but so does the ability to fund the machine behind the models: training clusters, inference capacity, developer ecosystems, enterprise sales, consumer distribution, and increasingly the tooling layer around coding and automation. That is what makes this moment important. Frontier AI is becoming less like launching an app and more like building a power grid. The technology may feel abstract, but the economics are becoming brutally concrete. Intelligence is expensive to manufacture, even more expensive to serve, and the companies that can keep feeding that loop are building an advantage that is not easy to copy.</p><p>Microsoft’s releases made a different point, but one that is just as important. With MAI-Transcribe-1, MAI-Voice-1, and MAI-Image-2, Microsoft is signaling that it does not want to be merely the best host for other people’s intelligence. It wants to own more of the intelligence layer itself. That is a meaningful shift. In the first phase of the generative AI boom, large platforms won by embedding frontier models into existing products. In the next phase, they may win by controlling the core modalities that define how software feels and behaves. Speech, voice, and image generation are no longer side features. They are becoming native interfaces. The future office suite may not be built around files and menus, but around systems that can hear, speak, see, and create in real time.</p><p>Google’s Gemma 4 pushes from the opposite direction and, in some ways, makes the market more interesting. If OpenAI represents scale and Microsoft represents vertical integration, Gemma 4 represents the growing strategic importance of openness. Open models are no longer just the rebel wing of AI. They are becoming essential pieces of the deployment stack, especially for developers and companies that want control, portability, and lower-cost inference. That matters because the next AI wave will not be won on raw benchmark prestige alone. It will be won on usability. Small, efficient, customizable models that can run closer to the edge may shape more real products than the most powerful model in the world sitting behind a distant API.</p><p>Then there is GLM-5V Turbo, which quietly points to where the agent era is going. Its importance is not just that it is multimodal. It is the type of multimodality that matters: interfaces, files, screens, visual reasoning, coding workflows. That is a different category of capability. It suggests a future in which models do not just generate text, but operate across software environments with something closer to functional competence. They do not merely describe what is on the screen. They begin to work through it.</p><p>That is why this week felt bigger than the individual announcements. The AI market is maturing from spectacle to systems. OpenAI is consolidating the economics of scale. Microsoft is building first-party control across modalities. Google is making the open layer harder to ignore. GLM-5V Turbo is pushing models closer to action. For the last two years, AI has often been discussed as if it were a product category. This week was a reminder that it is becoming something much larger: a new computing substrate. And once a technology becomes substrate, the real competition is no longer about who is smartest. It is about who becomes unavoidable.</p><p>🔎 AI Research</p><p><a href="https://arxiv.org/html/2507.22229v1" target="_blank" rel="noreferrer">TRIBE: TRImodal Brain Encoder for whole-brain fMRI response prediction</a></p><p>AI Lab: FAIR at Meta</p><p>Summary: TRIBE v2 is a tri-modal foundation model trained on over 1,000 hours of fMRI data to accurately predict human brain activity in response to video, audio, and language stimuli. It drastically outperforms traditional linear encoding models and enables in-silico neuroscience experiments by successfully replicating classic visual and neuro-linguistic findings while revealing the fine-grained topography of multisensory integration.</p><p><a href="https://arxiv.org/html/2604.00073v1" target="_blank" rel="noreferrer">Terminal Agents Suffice for Enterprise Automation</a></p><p>AI Lab: ServiceNow, Mila Quebec AI Institute, Université de Montréal</p><p>Summary: This paper challenges the necessity of complex web and tool-augmented agents for enterprise tasks by demonstrating that minimal coding agents equipped only with a terminal and direct API access perform just as well or better. By evaluating across diverse production-grade platforms, the authors show that these simpler terminal agents are significantly more cost-efficient and resilient without sacrificing effectiveness.</p><p><a href="https://arxiv.org/html/2603.26017v1" target="_blank" rel="noreferrer">QUITOBENCH: A High-Quality Open Time Series Forecasting Benchmark</a></p><p>AI Lab: Ant Group</p><p>Summary: To address the scarcity of reliable time series forecasting evaluations, this paper introduces QUITOBENCH, a regime-balanced benchmark derived from a billion-scale corpus of Alipay application traffic. The evaluation reveals that context length and forecastability are primary drivers of performance, demonstrating that smaller, task-specific deep learning models can actually match or outperform much larger foundation models.</p><p><a href="https://arxiv.org/html/2604.01193v1" target="_blank" rel="noreferrer">Embarrassingly Simple Self-Distillation Improves Code Generation</a></p><p>AI Lab: Apple</p><p>Summary: This research demonstrates that large language models can substantially improve their code generation capabilities by fine-tuning exclusively on their own raw, unverified outputs. This simple self-distillation approach works by resolving the precision-exploration conflict, allowing the model to suppress distractor tokens at rigid syntactic checkpoints while preserving diverse alternatives at creative branching points.</p><p><a href="https://arxiv.org/html/2503.06378v2" target="_blank" rel="noreferrer">General scales unlock AI evaluation with explanatory and predictive power</a></p><p>AI Lab: Princeton University, University of Cambridge, Microsoft Research Asia</p><p>Summary: The authors introduce a new methodology using 18 standardized rubrics to systematically profile both the cognitive demands of tasks and the intrinsic capabilities of AI models. This approach yields high predictive power for AI performance on unseen, out-of-distribution tasks by evaluating fundamental abilities rather than relying on easily saturated and heavily confounded benchmark aggregates.</p><p><a href="https://ojs.aaai.org/index.php/AAAI/article/view/39659" target="_blank" rel="noreferrer">Forest vs Tree: The (N, K) Trade-off in Reproducible ML Evaluation</a></p><p>AI Lab: Rochester Institute of Technology, Google Research</p><p>Summary: This study investigates the trade-off between the number of evaluation items and the number of human annotations per item when operating under a fixed budget for machine learning model assessment. The findings indicate that strategically collecting a higher number of annotations per item—rather than just scaling the total number of items—provides more statistically reliable evaluations, especially for metrics sensitive to human disagreement.</p><p>🤖 AI Tech Releases</p><p>Microsoft New AI Models</p><p>Microsoft <a href="https://microsoft.ai/news/today-were-announcing-3-new-world-class-mai-models-available-in-foundry/" target="_blank" rel="noreferrer">announced 3 state-of-the-art models</a>, MAI-Transcribe-1, MAI-Voice-1 and MAI-Image-2 that enable transcruption, audio processing and image generation capabilities.</p><p>Gemma 4</p><p>Google DeepMind <a href="https://blog.google/innovation-and-ai/technology/developers-tools/gemma-4/" target="_blank" rel="noreferrer">released Gemma 4</a>, its highly efficient small model optimized for reasoning.</p><p>GLM-5V Turbo</p><p>Z.ai <a href="https://x.com/Zai_org/status/2039371126984360085" target="_blank" rel="noreferrer">open sourced GML-5V Turbo </a>with new multimodal coding capabilities and optimization for Claw scenarios.</p><p>Trinity Large Thinking</p><p>Arcee AI <a href="https://www.arcee.ai/blog/trinity-large-thinking" target="_blank" rel="noreferrer">open sourced Trinity Large Thinking</a>, its largest open source frontier agent.</p><p>📡AI News You Need to Know About</p><p><a href="https://openai.com/index/accelerating-the-next-phase-ai/" target="_blank" rel="noreferrer">OpenAI closed a $122 billion funding </a>round at an $852 billion valuation, backed by Amazon, NVIDIA, SoftBank, and Microsoft, to scale compute infrastructure, expand its API and Codex platforms, and build toward a unified AI “superapp.”</p><p><a href="https://www.bloomberg.com/news/articles/2026-04-02/india-ai-startup-sarvam-raises-funds-at-1-5-billion-valuation" target="_blank" rel="noreferrer">India’s Sarvam AI is nearing a $300–350M raise at a ~$1.5B valuation </a>led by Bessemer Venture Partners, with NVIDIA, Amazon, and Prosperity7 also participating, positioning it as a domestic AI challenger with voice-first, multilingual models covering 22 Indian languages.</p><p><a href="https://openai.com/index/openai-acquires-tbpn/" target="_blank" rel="noreferrer">OpenAI acquired TBPN</a>, a popular daily tech/business talk show hosted by founders John Coogan and Jordi Hays, marking the AI company’s first media acquisition ahead of its planned IPO; the show will report to OpenAI’s strategy team under Chris Lehane.</p><p><a href="https://blog.yupp.ai/winddown" target="_blank" rel="noreferrer">Yupp, the crowdsourced AI model evaluation startup that raised $33M from a16z crypto’s Chris Dixon, is shutting down</a> less than a year after launch, citing insufficient product-market fit as the industry shifted toward agentic systems and expert-led feedback.</p><p><a href="https://scaleops.com/blog/scaleops-series-c/" target="_blank" rel="noreferrer">ScaleOps raised $130M in Series C </a>funding at a valuation above $800M, led by Insight Partners, for its platform that autonomously manages and reallocates Kubernetes-based cloud and AI compute resources in real time, claiming up to 80% cost reduction.</p><p><a href="https://rebellions.ai/newsroom/rebellions-closes-400-million-pre-ipo-and-launches-rebelrack-and-rebelpod-to-accelerate-global-expansion/" target="_blank" rel="noreferrer">South Korean fabless AI chip startup Rebellions raised $400M </a>in a pre-IPO round led by Mirae Asset and the Korea National Growth Fund, reaching a $2.34B valuation and $850M in total funding, while launching new inference infrastructure products and expanding into the U.S., Japan, and Saudi Arabia.</p><p><a href="https://www.reuters.com/business/finance/frances-mistral-raises-830-million-debt-ai-data-centre-build-up-2026-03-30/" target="_blank" rel="noreferrer">French AI lab Mistral raised $830M in debt financing </a>to build a new Nvidia-powered data center near Paris, expected to become operational in Q2 2026.</p><p><a href="https://www.qodo.ai/blog/qodo-70m-series-b-shift-to-artificial-wisdom/" target="_blank" rel="noreferrer">Qodo raised $70M in Series B </a>funding led by Qumra Capital, bringing total funding to $120M, to scale its AI-powered code review and governance platform that verifies AI-generated code against organizational standards, used by enterprises like NVIDIA, Walmart, and Red Hat.</p><p><a href="http://businesswire.com/news/home/20260330024111/en/Starcloud-Raises-%24170M-Series-A-at-%241.1bn-Valuation-Led-by-Benchmark-and-EQT-Ventures" target="_blank" rel="noreferrer">Y Combinator alum Starcloud raised $170M in a Series A </a>led by Benchmark and EQT Ventures at a $1.1B valuation, becoming one of the fastest YC startups to reach unicorn status, as it develops orbital data centers designed to launch aboard SpaceX’s Starship.</p><p><a href="https://www.rdworldonline.com/anthropics-400m-acquisition-of-coefficient-bio-signals-a-deeper-push-into-drug-discovery/" target="_blank" rel="noreferrer">Anthropic acquired Coefficient Bio</a>, a Dimension-backed stealth biotech AI startup founded roughly eight months ago with fewer than 10 employees, for approximately $400M in stock, bringing in a team of former Genentech researchers building biology-specific AI models to join Anthropic’s Health Care Life Sciences group as the company pushes to make Claude the leading model for drug discovery, R&amp;D planning, and clinical regulatory strategy.</p><hr>',57)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
